qry:select.qry:xquery:
					for $r in SQL('
{%? (#SOURCE:@START='') {% %} {% fromrow {%=#SOURCE:@START %} %} %} 
 {%? (#SOURCE:@LEN='') {% %} {% maxsize {%=#SOURCE:@LEN %} %} %} 
select
  CYD02_DICTADOS.oi_dictado as ID,
  CYD02_DICTADOS.c_dictado as COD,
  CYD02_DICTADOS.d_dictado as DES,
  CYD02_DICTADOS.oi_curso as PARENT
from
  CYD02_DICTADOS
Where
  1=1 
{%? (#SOURCE:@OI_FIND='') {% %} {% and ID={#SOURCE:@OI_FIND} %} %} 
{%? (#SOURCE:@TXT_FIND='') {% %} {% and (contain(DES,{#SOURCE:@TXT_FIND}) or contain(COD,{#SOURCE:@TXT_FIND})) %} %} 
{%? (#SOURCE:@OI_PARENT='') {% %} {% and PARENT={#SOURCE:@OI_PARENT} %} %} 

{%? (#SOURCE:@WHERE='') {% %} {% and {%=#SOURCE:@WHERE %} %} %}
{%? (#SOURCE:@ORDERBY='') {% order by DES asc %} {%  order by {%=#SOURCE:@ORDERBY %} asc %} %}')/ROWS/ROW

					for $r in sql('  
SELECT 
	DIC.oi_dictado,
	DIC.f_inicio
FROM 
	CYD02_DICTADOS AS DIC,
	CYD01_CURSOS AS CUR
	{%? (#F:@oi_area != '' OR #F:@oi_curso != '') 
		{% , ORG06_CURSOS AS AREA%} {% %} %}
	{%? (#F:@oi_competencia != '') 
		{% ,CYD01_COMP_CURSO %} {% %} %}
	{%? (#F:@oi_docente != '') 
		{% ,CYD02_DOC_DICTADO %} {% %} %}

JOIN 
	DIC.oi_curso INNER CUR.oi_curso
	{%? (#F:@oi_area != '' OR #F:@oi_curso != '') 
		{% ,CUR.oi_area INNER AREA.oi_curso%} {% %} %}
	{%? (#F:@oi_competencia != '') 
		{% ,CUR.oi_curso LEFT OUTER CYD01_COMP_CURSO.oi_curso %} {% %} %}
	{%? (#F:@oi_docente != '') 
		{% ,DIC.oi_dictado LEFT OUTER CYD02_DOC_DICTADO.oi_dictado %} {% %} %}

WHERE             
	 DIC.f_inicio <= {Datetime(#F:@f_hasta)} 
	 AND DIC.f_fin >= {Datetime(#F:@f_desde)}
	 {%? (#F:@oi_lugar_dictado != '') {% AND DIC.oi_lugar_dictado  = {#F:@oi_lugar_dictado} %} {% %} %}
	 {%? (#F:@oi_docente !='') {% AND CYD02_DOC_DICTADO.oi_docente = {#F:@oi_docente} %} {% %} %}
	 {%? (#F:@oi_proveedor != '') {% AND DIC.oi_proveedor = {#F:@oi_proveedor} %} {% %} %}
	 {%? (#F:@oi_dictado != '') {% AND DIC.oi_dictado = {#F:@oi_dictado} %} {% %} %}
	 {%? (#F:@c_tipo_asistencia != '') {% AND DIC.c_tipo_asistencia = {#F:@c_tipo_asistencia} %} {% %} %}
	 {%? (#F:@c_estado != '') {% AND DIC.c_estado = {#F:@c_estado} %} {% %} %}
	 {%? (#F:@oi_area != '') {% AND AREA.oi_curso = {#F:@oi_area} %} {% %} %}
	 {%? (#F:@oi_curso != '') {% AND CUR.oi_curso = {#F:@oi_curso} %} {% %} %}
	 {%? (#F:@oi_tipo_curso != '') {% AND CUR.oi_tipo_curso = {#F:@oi_tipo_curso} %} {% %} %}
	 {%? (#F:@oi_categ_curso != '') {% AND CUR.oi_categ_curso = {#F:@oi_categ_curso} %} {% %} %}
	 {%? (#F:@oi_competencia != '') {% AND CYD01_COMP_CURSO.oi_competencia = {#F:@oi_competencia} %} {% %} %}
	 {%? (#F:@oi_estructura != '') {% AND DIC.oi_estructura = {#F:@oi_estructura} %} {% %} %}
ORDER BY                            
	f_inicio ASC 
')/ROWS

					for $r in SQL('{%? (#FILTER:@LEN='') {% %} {% maxsize {%=#FILTER:@LEN %} %} %}
SELECT 
  CYD02_FACT_EV_AS.oi_fact_ev_as as ID, 
  CYD02_FACT_EV_AS.oi_eval_asist as PAR, 
  CYD12_FACTORES_EVAL.c_factor as COD, 
  CYD12_FACTORES_EVAL.d_factor as DES
{%?($FILTER/@order!='') {% ,CYD02_FACT_EV_AS.{%=$FILTER/@order %} as COL_ORDER %} {% %} %}
FROM 
  CYD02_FACT_EV_AS, 
  CYD12_FACTORES_EVAL
JOIN 
  CYD02_FACT_EV_AS.oi_factor_eval LEFT OUTER CYD12_FACTORES_EVAL.oi_factor_eval
WHERE 1=1

{%?($FILTER/@parent!='') {% and PAR={$FILTER/@parent} %} {% %} %}

{%?($FILTER/@search!='')
 {% and (contain(ucase(DES),{upper-case($FILTER/@search)}) or contain(ucase(COD),{upper-case($FILTER/@search)})) %}
 {% %}
%}

{%?($FILTER/@order!='')
  {% order by COL_ORDER {%=iif($FILTER/@asc='1','asc','desc') %} %}
  {% %}
%}
')/ROWS/ROW
